import { MovieProfile } from '../movie-profile';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { LoadingPage } from '../loading-page';
import { Link } from 'react-router-dom';
import { formatLanguageToApi } from '../utils/api-utils';
import { useLanguage } from '../../context/language';
// import { useTheme} from '../../context/theme';

interface MoviesInformation {
	page?: number;
	results: any;
	total_pages?: number;
	total_results?: number;
}

export function HomePage() {
	const [movies, setMovies] = useState<MoviesInformation>({ results: [] });
	const [isLoading, setIsLoading] = useState(false);

	const { language } = useLanguage();
	// const { theme } = useTheme();

	const token = 'Bearer ' + process.env.REACT_APP_TMDB_BEARER_TOKEN;
	const testUrl = `https://api.themoviedb.org/3/movie/top_rated?api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;

	async function getMovieData() {
		setIsLoading(true);
		const response = await axios({
			method: 'get',
			url: testUrl,
			headers: { Authorization: token }
		});
		setMovies(response.data);
		setIsLoading(false);
	}

	useEffect(() => {
		getMovieData();
	}, [language]);

	return (
		<div>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className="bg-[url('/Users/denzelwallace/Desktop/Me/Estudos/React/dmdb-app/public/assets/background.jpg')] bg-cover backdrop-blur-3xl bg-center text-center p-72">
						<p className='text-9xl font-extrabold'>Título</p>
						<p className='text-2xl'> Subtítulo</p>

					</div>
					<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
						{movies.results.map((movie: any) => {
							return (
								<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
									<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
								</Link>
							);
						})}
					</div>
				</>
			)}
		</div>
	);
}
